import type { PaginationParams, PaginatedResponse, Partner } from '~/types'

export function usePartnersApi() {
    const { $api } = useNuxtApp()

    return {
        findAll(params?: PaginationParams & { status?: string }) {
            return $api<PaginatedResponse<Partner>>('/partners', { params })
        },
        findById(id: string) {
            return $api<Partner>(`/partners/${id}`)
        },
        update(id: string, data: Partial<Partner>) {
            return $api<any>(`/partners/${id}`, { method: 'PUT', body: data })
        },
        approve(id: string) {
            return $api<any>(`/partners/${id}/approve`, { method: 'PATCH' })
        },
        suspend(id: string, reason: string) {
            return $api<any>(`/partners/${id}/suspend`, { method: 'PATCH', body: { reason } })
        },
    }
}
